mapper.select:
SELECT a.id,a.create_time,a.delete_time,finish_time,latest_fail_reason,logs,model,prompt,refer_images,result_images,retry_num,size,status,third_task_id,a.update_time,user_id, b.uuid,b.nickname FROM nano_tasks a left join users b on a.user_id = b.id
a.status = 2
and b.uuid = #{uuid}
ORDER BY a.create_time DESC limit #{startIndex},#{pageSize}

SELECT count(a.id) FROM nano_tasks a left join users b on a.user_id = b.id
a.status = 2
and b.uuid = #{uuid}

SELECT a.id,a.create_time,a.delete_time,a.finish_time,a.latest_fail_reason,a.logs,a.model, a.prompt,a.refer_images,a.result_images,a.retry_num,a.size,a.status,a.third_task_id, a.update_time,a.user_id ,b.status as hp_status, b.result_image as hp_result_image FROM nano_tasks a left join nano_tasks_hp b on a.id = b.task_id
${ew.customSqlSegment}
ORDER BY a.create_time

SELECT count(0) FROM nano_tasks a
    ${ew.customSqlSegment}
ORDER BY a.create_time
